package com.carland.carland_service.service.impl;import com.carland.carland_service.dto.response.HyperTokenResponse;import com.carland.carland_service.exceptions.MissingFieldException;import com.carland.carland_service.feign.HyperAuthClient;import lombok.RequiredArgsConstructor;import lombok.extern.slf4j.Slf4j;import org.springframework.beans.factory.annotation.Value;import org.springframework.cache.Cache;import org.springframework.cache.CacheManager;import org.springframework.scheduling.annotation.Scheduled;import org.springframework.stereotype.Service;import org.springframework.util.LinkedMultiValueMap;import org.springframework.util.MultiValueMap;/** * Service responsible for managing Hyper authentication tokens. * * This service handles the complete lifecycle of the Hyper Bearer token, including: * - Fetching a new token from Hyper Auth service using client credentials flow * - Caching the token to avoid unnecessary authentication requests * - Providing a centralized access point for all Hyper API integrations * - Periodically refreshing the token before expiration to ensure continuity * * Token Strategy: * - Tokens are cached in application-level cache ("hyper") * - Cache key: "hyper_token" * - Token lifetime: 1 hour (as defined by Hyper Auth service) * - Refresh interval: 59 minutes (scheduled refresh to prevent expiration gaps) * * Rate Limiting Consideration: * - Hyper Auth endpoint is limited to 20 requests per hour * - This service ensures the limit is not exceeded by enforcing caching strategy * * Usage: * All Hyper-related API clients must retrieve the token via this service * to ensure consistent authentication handling and prevent duplicate token requests. */@Service@RequiredArgsConstructor@Slf4jpublic class HyperTokenService {    private final HyperAuthClient hyperAuthClient;    private static final String CACHE_KEY = "hyper_token";    private final CacheManager cacheManager;    @Value("${hyper.auth.client-id}")    private String clientId;    @Value("${hyper.auth.client-secret}")    private String clientSecret;    /**     * Refreshes the cached Hyper token every 59 minutes.     * Prevents token expiration and avoids excessive requests     * to the Hyper authentication endpoint.     */    @Scheduled(fixedRate = 59 * 60 * 1000)    public void refreshToken() {        fetchTokenAndCache();    }    /**     * Requests a new access token from Hyper Authentication Service using     * client credentials flow and stores the token in cache.     *     * This method is responsible for:     * - Building authentication request payload     * - Calling Hyper Auth API via Feign client     * - Validating response integrity     * - Extracting access token from response     * - Caching the token for reuse in subsequent requests     *     * In case of failure, the error is logged and null is returned.     */    private String fetchTokenAndCache() {        try {            MultiValueMap<String, String> form = new LinkedMultiValueMap<>();            form.add("grant_type", "client_credentials");            form.add("client_id", clientId);            form.add("client_secret", clientSecret);            HyperTokenResponse response = hyperAuthClient.getToken(form);            if (response == null || response.getAccessToken() == null) {                throw new MissingFieldException("Hyper service token response is null");            }            log.info("HyperTokenResponse {}", response);            String token = response.getAccessToken();            Cache cache = cacheManager.getCache("hyper");            if (cache != null) {                cache.put(CACHE_KEY, token);                log.info("token putting into cache");            }            log.info("token fetch process is successful");            return token;        } catch (Exception e) {            log.error("Token fetch error", e);            return null;        }    }    /**     * Retrieves a valid Hyper Bearer token for authenticated API calls.     *     * This method is the single entry point for obtaining authentication tokens     * used across all Hyper API integrations.     *     * Workflow:     * - First checks cached token     * - If cached token exists, returns it immediately     * - If not found or expired, requests a new token from Hyper Auth Service     *   and updates the cache     *     * All downstream services must use this method to ensure consistent     * authentication handling and to avoid exceeding Hyper rate limits.     */    public String getToken() {        Cache cache = cacheManager.getCache("hyper");        if (cache != null) {            String token = cache.get(CACHE_KEY, String.class);            if (token != null)                return token;        }        return fetchTokenAndCache();    }}